# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

from flask import Flask, redirect, url_for, render_template_string, request, session
import requests
import urllib.parse

app = Flask(__name__)

AUTH_SERVER = "https://your-auth-server.com"
CLIENT_ID = "your_client_id"
CLIENT_SECRET = "your_client_secret"

REDIRECT_URI = url_for('callback', _external=True)

@app.route('/login')
def login():
    auth_url = f"{AUTH_SERVER}/oauth2/authorize?client_id={CLIENT_ID}&redirect_uri={urllib.parse.quote(REDIRECT_URI)}&response_type=code"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded'
    }
    data = f"grant_type=authorization_code&code={code}&redirect_uri={urllib.parse.quote(REDIRECT_URI)}&client_id={CLIENT_ID}&client_secret={CLIENT_SECRET}"
    response = requests.post(f"{AUTH_SERVER}/oauth2/token", headers=headers, data=data)
    access_token = response.json().get('access_token')
    session['access_token'] = access_token
    return 'Logged in successfully!'

if __name__ == '__main__':
    app.run(debug=True)